    'Travel Recovery Routine',
    'Travel Recovery Routine - 2w 7x/wk',
    'Low',
    false,
    'Recovery stretching for travel days',
    'Warmup & Cooldown'
FROM program_variants pv
JOIN branded_programs bp ON bp.id = pv.base_program_id
WHERE bp.name = 'Travel Recovery Routine'
  AND pv.duration_weeks = 2
  AND pv.sessions_per_week = 7
ON CONFLICT DO NOTHING;
